import React, { useState } from 'react';
import {
  Box,
  Card,
  CardContent,
  Typography,
  IconButton,
  Chip,
} from '@mui/material';
import {
  FavoriteBorder,
  Favorite,
  ShoppingCart,
} from '@mui/icons-material';
import { ar } from '../../i18n/ar';
import { formatPrice } from '../../utils/formatCurrency';

function ProductCard({ product, onAddToCart }) {
  const [fav, setFav] = useState(false);
  const discount = Math.round(product.discountPercent || 0);

  return (
    <Card
      elevation={0}
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        border: '1px solid',
        borderColor: 'divider',
        borderRadius: 2,
        overflow: 'visible',
        position: 'relative',
        transition: 'box-shadow 0.2s, transform 0.2s',
        '&:hover': {
          boxShadow: 4,
          transform: 'translateY(-2px)',
        },
      }}
    >
      <Box
        sx={{
          px: 1,
          pt: 1,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
        }}
      >
        <IconButton
          size="small"
          aria-label="مفضلة"
          onClick={() => setFav(!fav)}
          sx={{ color: fav ? 'error.main' : 'action.active' }}
        >
          {fav ? <Favorite /> : <FavoriteBorder />}
        </IconButton>
        <Chip
          label={`-${discount}%`}
          size="small"
          sx={{
            bgcolor: 'success.main',
            color: 'white',
            fontWeight: 800,
            fontSize: '0.75rem',
          }}
        />
      </Box>

      <Typography
        variant="caption"
        align="center"
        sx={{ px: 1, color: 'text.secondary', fontWeight: 600 }}
      >
        {product.categoryLabel}
      </Typography>

      <Box
        sx={{
          height: 160,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          px: 2,
          py: 1,
        }}
      >
        <Box
          component="img"
          src={product.image}
          alt={product.name}
          sx={{ maxHeight: '100%', maxWidth: '100%', objectFit: 'contain' }}
        />
      </Box>

      <CardContent sx={{ flexGrow: 1, pt: 1, pb: 1.5, px: 2 }}>
        <Typography
          variant="body2"
          align="center"
          sx={{ fontWeight: 700, mb: 0.5, minHeight: 40 }}
        >
          {product.name}
        </Typography>

        {product.specs ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', mb: 1 }}>
            <Chip label={product.specs} size="small" variant="outlined" />
          </Box>
        ) : (
          <Box sx={{ mb: 1, minHeight: 32 }} />
        )}

        <Box
          sx={{
            display: 'flex',
            alignItems: 'baseline',
            justifyContent: 'center',
            gap: 1,
            flexWrap: 'wrap',
            mb: 1,
          }}
        >
          <Typography
            variant="body2"
            sx={{ textDecoration: 'line-through', color: 'text.secondary' }}
          >
            {formatPrice(product.originalPrice)} {ar.currency}
          </Typography>
          <Typography variant="h6" sx={{ color: 'success.main', fontWeight: 800 }}>
            {formatPrice(product.currentPrice)} {ar.currency}
          </Typography>
        </Box>

        <Box sx={{ display: 'flex', justifyContent: 'center', mt: 'auto' }}>
          <IconButton
            onClick={() => onAddToCart?.(product)}
            sx={{
              bgcolor: 'grey.800',
              color: 'white',
              borderRadius: 1,
              '&:hover': { bgcolor: 'grey.900' },
            }}
            aria-label={ar.addToCart}
          >
            <ShoppingCart fontSize="small" />
          </IconButton>
        </Box>
      </CardContent>
    </Card>
  );
}

export default ProductCard;
