import React from 'react';
import { Box, Typography, Grid, Link, Skeleton } from '@mui/material';
import { East } from '@mui/icons-material';
import ProductCard from '../product/ProductCard';
import { ar } from '../../i18n/ar';

function ProductRowSection({
  title,
  count,
  products,
  loading,
  variant = 'limited',
  onAddToCart,
  viewAllHref = '#',
}) {
  const barSx =
    variant === 'featured'
      ? {
          background: 'linear-gradient(90deg, #0d47a1 0%, #1565c0 100%)',
        }
      : { bgcolor: 'grey.900' };

  return (
    <Box sx={{ mb: 4 }}>
      <Box
        sx={{
          ...barSx,
          color: 'white',
          py: 1.5,
          px: 2,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          borderRadius: '8px 8px 0 0',
        }}
      >
        <Typography variant="subtitle1" fontWeight={800}>
          {title}
        </Typography>
        <Box
          sx={{
            bgcolor: 'error.main',
            color: 'white',
            px: 1.5,
            py: 0.5,
            borderRadius: 1,
            fontWeight: 700,
            fontSize: '0.85rem',
          }}
        >
          {ar.productsCount(count)}
        </Box>
      </Box>
      <Box
        sx={{
          bgcolor: 'background.paper',
          p: 2,
          border: '1px solid',
          borderColor: 'divider',
          borderTop: 0,
          borderRadius: '0 0 8px 8px',
        }}
      >
        {loading ? (
          <Grid container spacing={2}>
            {[1, 2, 3, 4, 5, 6].map((i) => (
              <Grid item xs={6} sm={4} md={2} key={i}>
                <Skeleton variant="rectangular" height={280} />
              </Grid>
            ))}
          </Grid>
        ) : (
          <Grid container spacing={2}>
            {(products || []).map((p) => (
              <Grid item xs={6} sm={4} md={2} key={p._id}>
                <ProductCard product={p} onAddToCart={onAddToCart} />
              </Grid>
            ))}
          </Grid>
        )}
        <Box sx={{ textAlign: 'center', mt: 2 }}>
          <Link
            href={viewAllHref}
            underline="hover"
            sx={{
              color: 'warning.dark',
              fontWeight: 700,
              display: 'inline-flex',
              alignItems: 'center',
              gap: 0.5,
            }}
          >
            {ar.viewAllDeals} ... {title}
            <East sx={{ fontSize: 18, transform: 'scaleX(-1)' }} />
          </Link>
        </Box>
      </Box>
    </Box>
  );
}

export default ProductRowSection;
